from jinja2 import Environment

env = Environment(extensions=['jinja2.ext.i18n'])

def dgettext(domain, s):
    return f'[{domain}] {s}'

def dngettext(domain, s, p, n):
    return f'[{domain}] ' + (s if n == 1 else p)

def gettext(s):
    return s

def ngettext(s, p, n):
    return s if n == 1 else p

env.install_gettext_callables(gettext, ngettext, newstyle=True, dgettext=dgettext, dngettext=dngettext)

t = env.from_string('{% trans domain=\"admin\" %}Hello{% endtrans %}')
print(t.render())

t2 = env.from_string('{% trans domain=\"admin\" count=3 %}{{ count }} item{% pluralize %}{{ count }} items{% endtrans %}')
print(t2.render(count=3))

t2b = env.from_string('{% trans count=3, domain=\"admin\" %}{{ count }} item{% pluralize %}{{ count }} items{% endtrans %}')
print(t2b.render())

t3 = env.from_string('{% trans %}Hello{% endtrans %}')
print(t3.render())

# error cases
try:
    env.from_string('{% trans domain=\"a\", domain=\"b\" %}x{% endtrans %}')
except Exception as e:
    print(type(e).__name__, e)

try:
    env.from_string('{% trans domain=somevar %}x{% endtrans %}')
except Exception as e:
    print(type(e).__name__, e)
